window.chineseSwitcher={twContent:null,cnContent:null,converter:null,init:function(){window.OpenCC?(this.converter=OpenCC.Converter({from:"tw",to:"cn"}),this.initSwitcher()):(console.log("等待 OpenCC 載入..."),setTimeout(()=>this.init(),100))},initSwitcher:function(){const e=document.querySelector("article");if(!e)return;this.twContent=e.innerHTML;const n=document.querySelector('[data-lang="zh-tw"]'),t=document.querySelector('[data-lang="zh-cn"]');if(!n||!t)return;t.addEventListener("click",()=>{if(t.classList.contains("active"))return;if(n.classList.contains("active")&&(this.twContent=e.innerHTML),this.cnContent)e.innerHTML=this.cnContent;else{const t=e.querySelectorAll(".bookmark-highlight"),n=[];t.forEach((e,t)=>{n[t]=e.textContent;const s=document.createTextNode(e.textContent);e.parentNode.replaceChild(s,e)});const s=e.innerHTML;e.innerHTML=this.converter(s),this.cnContent=e.innerHTML,window.bookmark&&window.bookmark.loadHighlights()}t.classList.add("active"),n.classList.remove("active"),localStorage.setItem("preferredChinese","cn")}),n.addEventListener("click",()=>{if(n.classList.contains("active"))return;t.classList.contains("active")&&(this.cnContent=e.innerHTML),e.innerHTML=this.twContent,n.classList.add("active"),t.classList.remove("active"),localStorage.setItem("preferredChinese","tw")});const s=localStorage.getItem("preferredChinese");s==="cn"&&setTimeout(()=>t.click(),100),console.log("繁簡切換初始化完成")},updateContent:function(e,t){e==="tw"&&(this.twContent=t),e==="cn"&&(this.cnContent=t)}}